DELETE FROM app_support_ticket_message
WHERE ticket_id IN (
    SELECT id FROM (
        SELECT id
        FROM app_support_ticket
        WHERE user_id = #{userId}
           OR character_id IN (
                SELECT id FROM (
                    SELECT id
                    FROM app_character
                    WHERE owner_user_id = #{userId}
                ) c
           )
    ) t
)

